import * as React from "react"

import { cn } from "@nhic/currantui/lib/utils"

function Card({
  className,
  size = "default",
  ...props
}: React.ComponentProps<"div"> & { size?: "default" | "sm" }) {
  return (
    <div
      data-slot="card"
      data-size={size}
      className={cn(
        "group/card flex flex-col gap-3 overflow-hidden rounded-lg bg-card py-(--card-spacing) text-sm/relaxed text-card-foreground border border-border shadow-[0_1px_2px_rgba(0,0,0,0.04)] [--card-spacing:--spacing(4)] has-[>img:first-child]:pt-0 data-[size=sm]:gap-2 data-[size=sm]:[--card-spacing:--spacing(3)] *:[img:first-child]:rounded-t-lg *:[img:last-child]:rounded-b-lg",
        className
      )}
      {...props}
    />
  )
}

/**
 * Full-bleed media area at the top of a Card: an image, a token gradient
 * (`from-primary-deep via-primary …`), or any visual. Cancels the card's top
 * padding; place it as the first child. Siblings that overlap it (avatars,
 * icon tiles) must be positioned (`relative`) or this positioned cover
 * paints over them.
 */
function CardCover({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-cover"
      className={cn(
        "relative -mt-(--card-spacing) h-36 w-full overflow-hidden bg-muted *:[img]:size-full *:[img]:object-cover",
        className
      )}
      {...props}
    />
  )
}

function CardHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-header"
      className={cn(
        "group/card-header @container/card-header grid auto-rows-min items-start gap-1 rounded-t-lg px-(--card-spacing) has-data-[slot=card-action]:grid-cols-[1fr_auto] has-data-[slot=card-description]:grid-rows-[auto_auto] [.border-b]:pb-(--card-spacing)",
        className
      )}
      {...props}
    />
  )
}

function CardTitle({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-title"
      className={cn("font-heading text-base font-semibold tracking-tight", className)}
      {...props}
    />
  )
}

function CardDescription({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-description"
      className={cn("text-sm/relaxed text-muted-foreground", className)}
      {...props}
    />
  )
}

function CardAction({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-action"
      className={cn(
        "col-start-2 row-span-2 row-start-1 self-start justify-self-end",
        className
      )}
      {...props}
    />
  )
}

function CardContent({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-content"
      className={cn("px-(--card-spacing)", className)}
      {...props}
    />
  )
}

function CardFooter({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="card-footer"
      className={cn(
        "flex items-center rounded-b-lg px-(--card-spacing) [.border-t]:pt-(--card-spacing)",
        className
      )}
      {...props}
    />
  )
}

export {
  Card,
  CardCover,
  CardHeader,
  CardFooter,
  CardTitle,
  CardAction,
  CardDescription,
  CardContent,
}

import * as React from "react"
import {
  GridList as AriaGridList,
  GridListItem as AriaGridListItem,
} from "react-aria-components"

import { CollectionCheckbox } from "@nhic/currantui/components/list-view"
import { cn } from "@nhic/currantui/lib/utils"
import type {
  GridListItemProps as AriaGridListItemProps,
  GridListProps as AriaGridListProps,
} from "react-aria-components"

/**
 * Card grid with list-view keyboard semantics: arrow keys move in two
 * dimensions, selection via `selectionMode`. Needs an accessible name via
 * `aria-label`; keep empty states inside `renderEmptyState`.
 */
function CardView<T extends object>({
  className,
  ...props
}: Omit<AriaGridListProps<T>, "className" | "layout"> & {
  className?: string
}) {
  return (
    <AriaGridList
      layout="grid"
      data-slot="card-view"
      className={cn(
        "grid w-full grid-cols-[repeat(auto-fill,minmax(14rem,1fr))] gap-2 outline-none data-[focus-visible]:ring-2 data-[focus-visible]:ring-ring/30 data-[empty]:block data-[empty]:py-6 data-[empty]:text-center data-[empty]:text-sm/relaxed data-[empty]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function CardViewItem({
  className,
  children,
  textValue,
  ...props
}: Omit<AriaGridListItemProps, "className" | "children"> & {
  className?: string
  children: React.ReactNode
}) {
  return (
    <AriaGridListItem
      data-slot="card-view-item"
      textValue={textValue}
      className={cn(
        "group/card-view-item relative flex flex-col overflow-hidden rounded-lg bg-card text-sm/relaxed text-card-foreground ring-1 ring-foreground/10 transition-shadow outline-none data-[hovered]:ring-foreground/25 data-[selected]:ring-2 data-[selected]:ring-primary data-[focus-visible]:ring-2 data-[focus-visible]:ring-ring data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
        className
      )}
      {...props}
    >
      {({ selectionMode, selectionBehavior }) => (
        <>
          {selectionMode !== "none" && selectionBehavior === "toggle" && (
            <CollectionCheckbox className="absolute top-2 end-2 z-10" />
          )}
          {children}
        </>
      )}
    </AriaGridListItem>
  )
}

export { CardView, CardViewItem }

