"use client"

import * as React from "react"
import { Tooltip as TooltipPrimitive } from "radix-ui"

import { cn } from "@nhic/currantui/lib/utils"

function TooltipProvider({
  delayDuration = 0,
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Provider>) {
  return (
    <TooltipPrimitive.Provider
      data-slot="tooltip-provider"
      delayDuration={delayDuration}
      {...props}
    />
  )
}

function Tooltip({
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Root>) {
  return <TooltipPrimitive.Root data-slot="tooltip" {...props} />
}

function TooltipTrigger({
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Trigger>) {
  return <TooltipPrimitive.Trigger data-slot="tooltip-trigger" {...props} />
}

function TooltipContent({
  className,
  sideOffset = 0,
  children,
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Content>) {
  return (
    <TooltipPrimitive.Portal>
      <TooltipPrimitive.Content
        data-slot="tooltip-content"
        sideOffset={sideOffset}
        className={cn(
          "z-50 inline-flex w-fit max-w-xs origin-(--radix-tooltip-content-transform-origin) items-center gap-1.5 rounded-md bg-foreground px-3 py-1.5 text-sm text-background has-data-[slot=kbd]:pe-1.5 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 **:data-[slot=kbd]:relative **:data-[slot=kbd]:isolate **:data-[slot=kbd]:z-50 **:data-[slot=kbd]:rounded-sm data-[state=delayed-open]:animate-in data-[state=delayed-open]:fade-in-0 data-[state=delayed-open]:zoom-in-95 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95",
          className
        )}
        {...props}
      >
        {children}
        <TooltipPrimitive.Arrow className="z-50 size-2.5 translate-y-[calc(-50%-2px)] rotate-45 rounded-[2px] bg-foreground fill-foreground" />
      </TooltipPrimitive.Content>
    </TooltipPrimitive.Portal>
  )
}

export { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger }

import * as React from "react"
import {
  Button as AriaButton,
  Tree as AriaTree,
  TreeItem as AriaTreeItem,
  TreeItemContent as AriaTreeItemContent,
} from "react-aria-components"

import { CaretRightIcon } from "@phosphor-icons/react"
import { cn } from "@nhic/currantui/lib/utils"
import type {
  TreeItemProps as AriaTreeItemProps,
  TreeProps as AriaTreeProps,
} from "react-aria-components"

/**
 * Hierarchical list with expandable branches (one `TreeViewItem` nested in
 * another). Needs an accessible name via `aria-label`; expansion and
 * selection are controlled with `expandedKeys`/`selectedKeys` or their
 * `default*` counterparts.
 */
function TreeView<T extends object>({
  className,
  ...props
}: Omit<AriaTreeProps<T>, "className"> & { className?: string }) {
  return (
    <AriaTree
      data-slot="tree-view"
      className={cn(
        "flex w-full flex-col gap-0.5 outline-none data-[focus-visible]:ring-2 data-[focus-visible]:ring-ring/30 data-[empty]:py-6 data-[empty]:text-center data-[empty]:text-sm/relaxed data-[empty]:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

function TreeViewItem({
  title,
  icon,
  textValue,
  className,
  children,
  ...props
}: Omit<AriaTreeItemProps, "className" | "children" | "textValue"> & {
  className?: string
  /** Row content; nested TreeViewItems go in `children` */
  title: React.ReactNode
  icon?: React.ReactNode
  children?: React.ReactNode
  /** Derived from `title` when it is a plain string */
  textValue?: string
}) {
  return (
    <AriaTreeItem
      data-slot="tree-view-item"
      textValue={textValue ?? (typeof title === "string" ? title : "item")}
      className={cn(
        "group/tree-view-item rounded-md text-sm/relaxed transition-colors outline-none data-[hovered]:bg-accent data-[hovered]:text-accent-foreground data-[selected]:bg-accent data-[selected]:text-accent-foreground data-[focus-visible]:ring-2 data-[focus-visible]:ring-ring/30 data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
        className
      )}
      {...props}
    >
      <AriaTreeItemContent>
        {({ hasChildItems, level }) => (
          <div
            data-slot="tree-view-item-row"
            className="flex h-7 items-center gap-1 pe-2"
            style={{ paddingInlineStart: `${(level - 1) * 1.25 + 0.25}rem` }}
          >
            {hasChildItems ? (
              <AriaButton
                slot="chevron"
                data-slot="tree-view-item-chevron"
                className="flex size-5 shrink-0 items-center justify-center rounded-sm text-muted-foreground outline-none transition-colors data-[hovered]:bg-muted data-[hovered]:text-foreground data-[focus-visible]:ring-2 data-[focus-visible]:ring-ring/30"
              >
                <CaretRightIcon
                  aria-hidden="true"
                  className="size-4 transition-transform rtl:-scale-x-100 group-data-[expanded]/tree-view-item:rotate-90"
                />
              </AriaButton>
            ) : (
              <span aria-hidden="true" className="size-5 shrink-0" />
            )}
            {icon != null && (
              <span
                aria-hidden="true"
                className="flex size-4 shrink-0 items-center justify-center [&_svg]:size-4"
              >
                {icon}
              </span>
            )}
            <span className="truncate">{title}</span>
          </div>
        )}
      </AriaTreeItemContent>
      {children}
    </AriaTreeItem>
  )
}

export { TreeView, TreeViewItem }

