import type {ClassValue} from "clsx";

export function cn(...inputs: Array<ClassValue>) {
  return twMerge(clsx(inputs))
}

import * as React from "react"

/* Matches Tailwind's `max-lg:` exactly so CSS and JS agree on the breakpoint */
const MOBILE_QUERY = "(max-width: 1023px)"

function subscribe(callback: () => void) {
  const mql = window.matchMedia(MOBILE_QUERY)
  mql.addEventListener("change", callback)
  return () => mql.removeEventListener("change", callback)
}

function useIsMobile() {
  return React.useSyncExternalStore(
    subscribe,
    () => window.matchMedia(MOBILE_QUERY).matches,
    () => false
  )
}

export { useIsMobile }

import { resolveTokenColor } from "@nhic/currantui-charts/lib/theme"

import type { ImageExportOptions } from "@nhic/currantui-charts/lib/use-echart"

export function slugifyTitle(title: string): string {
  const slug = title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
  return slug || "chart"
}

function downloadUrl(url: string, filename: string): void {
  const anchor = document.createElement("a")
  anchor.href = url
  anchor.download = filename
  anchor.click()
}

/**
 * Export the rendered chart as an image. The card token is painted underneath
 * for both formats — JPEG has no alpha channel, and a transparent PNG would be
 * unreadable on mismatched surfaces.
 */
export function downloadChartImage(
  getDataURL: (options: ImageExportOptions) => string | undefined,
  options: { type: "png" | "jpeg"; title: string }
): void {
  const url = getDataURL({
    type: options.type,
    pixelRatio: 2,
    backgroundColor: resolveTokenColor("--card"),
  })
  if (!url) return
  const extension = options.type === "jpeg" ? "jpg" : "png"
  downloadUrl(url, `${slugifyTitle(options.title)}.${extension}`)
}

const numberFormat = new Intl.NumberFormat("en-US")

export function formatNumber(value: number): string {
  return numberFormat.format(value)
}

/** Table-cell display formatting; numbers get digit grouping, the rest passes through */
export function formatCell(value: unknown): string {
  if (typeof value === "number") return formatNumber(value)
  if (value == null) return ""
  return String(value)
}

import { formatNumber } from "@nhic/currantui-charts/lib/format"

import type { AxisOptions, ChartDataRow } from "@nhic/currantui-charts/lib/types"

/** Unique groups in first-appearance order — the fixed series order */
export function groupsOf(rows: ReadonlyArray<ChartDataRow>): Array<string> {
  return [...new Set(rows.map((row) => row.group))]
}

/** Unique category keys in first-appearance order */
export function keysOf(rows: ReadonlyArray<ChartDataRow>): Array<string | number> {
  return [...new Set(rows.map((row) => row.key))]
}

/** Per-group values aligned to `keys`, null where a group has no row */
export function valuesByGroup(
  rows: ReadonlyArray<ChartDataRow>,
  groups: ReadonlyArray<string>,
  keys: ReadonlyArray<string | number>
): Map<string, Array<number | null>> {
  const index = new Map<string, number>()
  rows.forEach((row) => index.set(`${row.group}\u0000${row.key}`, row.value))
  return new Map(
    groups.map((group) => [
      group,
      keys.map((key) => index.get(`${group}\u0000${key}`) ?? null),
    ])
  )
}

/**
 * Compact plot insets. `containLabel` reserves room for tick labels but not
 * axis names — pass which sides carry a name so it isn't clipped; the right
 * inset absorbs the last tick label's overhang.
 */
export function baseGrid(axisNames?: {
  left?: boolean
  bottom?: boolean
  right?: boolean
}): Record<string, unknown> {
  return {
    top: 12,
    right: axisNames?.right ? 30 : 24,
    bottom: axisNames?.bottom ? 34 : 4,
    // Covers the rotated name even when tick labels are narrow (single digits)
    left: axisNames?.left ? 40 : 4,
    containLabel: true,
  }
}

export function baseTooltip(
  valueFormatter?: (value: number) => string
): Record<string, unknown> {
  const format = valueFormatter ?? formatNumber
  return {
    confine: true,
    valueFormatter: (value: unknown) =>
      typeof value === "number" ? format(value) : String(value ?? ""),
  }
}

export function categoryAxis(
  labels: ReadonlyArray<string>,
  axis?: AxisOptions
): Record<string, unknown> {
  return {
    type: "category",
    data: [...labels],
    name: axis?.label,
    nameLocation: "middle",
    nameGap: 28,
  }
}

export function valueAxis(
  axis?: AxisOptions,
  valueFormatter?: (value: number) => string
): Record<string, unknown> {
  const format = axis?.formatter ?? valueFormatter ?? formatNumber
  return {
    type: "value",
    name: axis?.label,
    nameLocation: "middle",
    nameGap: 44,
    axisLabel: { formatter: (value: number) => format(value) },
  }
}

export interface HistogramBin {
  /** Inclusive lower edge */
  x0: number
  /** Exclusive upper edge (inclusive for the last bin) */
  x1: number
  count: number
}

/** Snap a raw width up to a readable 1/2/5 × 10^k step */
function niceWidth(raw: number): number {
  const magnitude = 10 ** Math.floor(Math.log10(raw))
  for (const step of [1, 2, 5, 10]) {
    if (raw <= step * magnitude) return step * magnitude
  }
  return 10 * magnitude
}

/**
 * Uniform-width binning; the bin count defaults to Sturges' rule and is a
 * target, not exact — widths snap to round 1/2/5 steps and edges align to
 * multiples of the width so bin labels read cleanly. `binWidth` takes
 * precedence over `bins` when both are given.
 */
export function binRows(
  values: ReadonlyArray<number>,
  options?: { bins?: number; binWidth?: number }
): Array<HistogramBin> {
  if (values.length === 0) return []
  const min = Math.min(...values)
  const max = Math.max(...values)
  const span = max - min
  if (span === 0) return [{ x0: min, x1: max, count: values.length }]

  const requestedBins = options?.bins ?? Math.ceil(Math.log2(values.length)) + 1
  const width = options?.binWidth ?? niceWidth(span / requestedBins)
  const start = Math.floor(min / width) * width
  const count = Math.max(1, Math.ceil((max - start) / width))
  const bins: Array<HistogramBin> = Array.from({ length: count }, (_, i) => ({
    x0: start + i * width,
    x1: start + (i + 1) * width,
    count: 0,
  }))
  values.forEach((value) => {
    const index = Math.min(count - 1, Math.floor((value - start) / width))
    const bin = bins[index]
    bin.count += 1
  })
  return bins
}

export interface BoxStats {
  /** Lower whisker: smallest sample within 1.5×IQR below Q1 */
  low: number
  q1: number
  median: number
  q3: number
  /** Upper whisker: largest sample within 1.5×IQR above Q3 */
  high: number
  outliers: Array<number>
}

/** Linear-interpolated (type-7) quantile of a sorted sample */
function quantileSorted(sorted: ReadonlyArray<number>, p: number): number {
  const position = (sorted.length - 1) * p
  const base = Math.floor(position)
  const lower = sorted[base]
  const upper = sorted[Math.min(base + 1, sorted.length - 1)]
  return lower + (upper - lower) * (position - base)
}

/** Five-number summary with 1.5×IQR whiskers; samples beyond them are outliers */
export function computeBoxStats(values: ReadonlyArray<number>): BoxStats | null {
  if (values.length === 0) return null
  const sorted = [...values].sort((a, b) => a - b)
  const q1 = quantileSorted(sorted, 0.25)
  const median = quantileSorted(sorted, 0.5)
  const q3 = quantileSorted(sorted, 0.75)
  const iqr = q3 - q1
  const lowFence = q1 - 1.5 * iqr
  const highFence = q3 + 1.5 * iqr
  // Never empty: the fences always contain the quartile samples themselves
  const inliers = sorted.filter((v) => v >= lowFence && v <= highFence)
  return {
    low: inliers[0],
    q1,
    median,
    q3,
    high: inliers[inliers.length - 1],
    outliers: sorted.filter((v) => v < lowFence || v > highFence),
  }
}

/**
 * Area-true size scale for bubble marks: symbol *area* grows linearly with
 * the value, so the rendered diameter follows the square root.
 */
export function scaleSqrt(
  domain: [number, number],
  range: [number, number]
): (value: number) => number {
  const [d0, d1] = domain
  const [r0, r1] = range
  const s0 = Math.sqrt(Math.max(0, d0))
  const s1 = Math.sqrt(Math.max(0, d1))
  if (s1 === s0) return () => (r0 + r1) / 2
  return (value) =>
    r0 + ((Math.sqrt(Math.max(0, value)) - s0) / (s1 - s0)) * (r1 - r0)
}

import type { CsvColumn } from "@nhic/currantui/lib/export-csv"
import type {
  ChartDataRow,
  PartDataRow,
} from "@nhic/currantui-charts/lib/types"

/** One column of the shell's table view; the same shape feeds the CSV export */
export type ChartTableColumn<TRow> = CsvColumn<TRow>

export function groupedRowColumns(headers?: {
  group?: string
  key?: string
  value?: string
}): Array<ChartTableColumn<ChartDataRow>> {
  return [
    { header: headers?.group ?? "Group", value: (row) => row.group },
    { header: headers?.key ?? "Key", value: (row) => row.key },
    { header: headers?.value ?? "Value", value: (row) => row.value },
  ]
}

export function partRowColumns(headers?: {
  group?: string
  value?: string
}): Array<ChartTableColumn<PartDataRow>> {
  return [
    { header: headers?.group ?? "Group", value: (row) => row.group },
    { header: headers?.value ?? "Value", value: (row) => row.value },
  ]
}

export const PALETTE_SIZE = 14

let sharedContext: CanvasRenderingContext2D | null = null

/**
 * Resolve any authored CSS color (oklch tokens included) to an rgba() string
 * via a 1x1 canvas readback — the canvas renderer's own color math only
 * understands hex/rgb/hsl, so tokens must not reach it as oklch strings.
 */
function resolveColor(value: string): string {
  sharedContext ??= document
    .createElement("canvas")
    .getContext("2d", { willReadFrequently: true })
  if (!sharedContext || !value) return value
  const ctx = sharedContext
  ctx.canvas.width = 1
  ctx.canvas.height = 1
  ctx.fillStyle = value
  ctx.fillRect(0, 0, 1, 1)
  const [r, g, b, a] = ctx.getImageData(0, 0, 1, 1).data
  return `rgba(${r}, ${g}, ${b}, ${(a / 255).toFixed(3)})`
}

/**
 * Resolve a CurrantUI token (e.g. "--card") to a concrete rgba() color.
 * Safe during server rendering (returns "") — option builders call this from
 * render, and the value is only consumed by the client-side canvas.
 */
export function resolveTokenColor(token: string, alpha?: number): string {
  if (typeof document === "undefined") return ""
  const value = getComputedStyle(document.documentElement)
    .getPropertyValue(token)
    .trim()
  const color = resolveColor(value)
  if (alpha === undefined) return color
  return color.replace(
    /rgba\((\d+), (\d+), (\d+), ([\d.]+)\)/,
    (_, r: string, g: string, b: string, a: string) =>
      `rgba(${r}, ${g}, ${b}, ${(Number(a) * alpha).toFixed(3)})`
  )
}

let paletteCache: { dark: boolean; colors: Array<string> } | null = null

function isDarkMode(): boolean {
  return document.documentElement.classList.contains("dark")
}

/** The CurrantUI dataviz palette (chart-1..14) resolved for the active theme */
export function getPalette(): Array<string> {
  const dark = isDarkMode()
  if (paletteCache?.dark !== dark) {
    const styles = getComputedStyle(document.documentElement)
    paletteCache = {
      dark,
      colors: Array.from({ length: PALETTE_SIZE }, (_, i) =>
        resolveColor(styles.getPropertyValue(`--chart-${i + 1}`).trim())
      ),
    }
  }
  return paletteCache.colors
}

/** Series color for a zero-based series index, in fixed palette order */
export function getPaletteColor(index: number): string {
  const palette = getPalette()
  return palette[index % palette.length] ?? ""
}

/**
 * CSS variable reference for a zero-based series index. Safe to use during
 * render (no DOM access) and theme-reactive for free — use for HTML surfaces
 * like legend swatches; the palette order matches the canvas series order.
 */
export function paletteVar(index: number): string {
  return `var(--chart-${(index % PALETTE_SIZE) + 1})`
}

/**
 * Build the token-driven ECharts theme for the active light/dark mode. Read at
 * chart init time so palette or token tuning never requires a charts release.
 */
export function buildChartTheme(): Record<string, unknown> {
  const styles = getComputedStyle(document.documentElement)
  const token = (name: string) => resolveColor(styles.getPropertyValue(name).trim())

  const inkMuted = token("--muted-foreground")
  const line = token("--border")
  const fontFamily = styles.getPropertyValue("--font-sans").trim() || "sans-serif"

  const axisText = {
    color: inkMuted,
    fontFamily,
    fontSize: 12,
  }
  const domainAxis = {
    axisLine: { show: true, lineStyle: { color: line } },
    axisTick: { show: false },
    axisLabel: axisText,
    nameTextStyle: axisText,
    splitLine: { show: false },
  }
  const measureAxis = {
    axisLine: { show: false },
    axisTick: { show: false },
    axisLabel: axisText,
    nameTextStyle: axisText,
    splitLine: { show: true, lineStyle: { color: line } },
  }

  return {
    color: getPalette(),
    textStyle: { color: inkMuted, fontFamily, fontSize: 12 },
    categoryAxis: domainAxis,
    valueAxis: measureAxis,
    timeAxis: domainAxis,
    logAxis: measureAxis,
    tooltip: {
      backgroundColor: token("--popover"),
      borderColor: line,
      textStyle: {
        color: token("--popover-foreground"),
        fontFamily,
        fontSize: 12,
      },
    },
    // Boxes default to a hardcoded white fill; use the card surface instead
    boxplot: {
      itemStyle: { color: token("--card"), borderWidth: 1.5 },
    },
  }
}

